using Microsoft.AspNetCore.Mvc; using SchoolEnterprise.Helpers; using SchoolEnterprise.Models.Domain; using SchoolEnterprise.Repositories; using SchoolEnterprise.Services;
namespace SchoolEnterprise.Controllers; [RoleGuard("Admin","Secretary")] public class ClassesController(ClassRepository repo, StudentRecordRepository records, SequenceService seq):Controller{ public IActionResult Index()=>View(repo.GetAll()); [HttpGet] public IActionResult Create()=>View(); [HttpPost] public IActionResult Create(ClassRoom t){t.ClassRoomId=seq.Next("ClassId"); repo.Add(t); return RedirectToAction(nameof(Index));} [HttpGet] public IActionResult Edit(int id)=>View(repo.GetById(id)); [HttpPost] public IActionResult Edit(ClassRoom t){repo.Update(t); return RedirectToAction(nameof(Index));} public IActionResult Delete(int id){repo.Delete(id); return RedirectToAction(nameof(Index));} public IActionResult Students(int id)=>View(records.GetByClass(id));}
